#include<bits/stdc++.h>
using namespace std;
int c[10001];
int n, a[1011], b[10011], ans = 1e6;
vector<int> q;
int main() {
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> a[i];

	}
	for (int i = 0; i < n; i++) {
		cin >> b[i];
	}
	q.resize(n);
	for (int i = 0; i < n; i++) {
		q[i] = i;
	}
	do {
		int len = n;
		for (int i = 1; i < n; i++) {
			len += max(b[q [i - 1] ], a[q [ i ] ]);
		}
		ans = min(ans, len);
	} while (next_permutation(q.begin(), q.end()));
	cout << ans << "\n";
	return 0;
}
